                Should -Throw "*TopN must be a positive integer*"
            { Get-TopConsumers -Processes $script:testProcesses -TopN -1 } |
                Should -Throw "*TopN must be a positive integer*"
        }

        It "throws for invalid SortBy value" {
            { Get-TopConsumers -Processes $script:testProcesses -SortBy "Disk" } |
